const crypto = require('crypto');
const secret = $env.VMP_WEBHOOK_SECRET || 'vmp-n8n-default-secret-change-me';
const signature = $input.first().headers['x-vmp-signature'] || '';
const body = JSON.stringify($input.first().body);
const expected = 'sha256=' + crypto.createHmac('sha256', secret).update(body).digest('hex');

if (signature && expected !== signature) {
  throw new Error('Firma HMAC inválida');
}

const company = $input.first().body.data;
return [{ json: { 
  ...company,
  isPremium: (company.cantidad_alumnos || 0) >= 50
}}];
